currentColor"/>\n              <path d="M12 2v4M12 18v4M2 12h4M18 12h4" stroke="currentColor"/>\n            </svg>\n            <span class="prod-int-hub-label">Data Hub</span>\n          </div>\n\n          <div class="prod-int-orbit">\n            <div class="prod-int-node prod-int-node--erp">\n              <div class="prod-int-node-icon">\n                <svg aria-hidden="true" viewBox="0 0 24 24">\n                  <rect x="3" y="3" width="18" height="18" rx="2"/>\n                  <path d="M3 9h18M9 21V9"/>\n                </svg>\n              </div>\n              <span class="prod-int-node-name">ERP</span>\n            </div>\n\n            <div class="prod-int-node prod-int-node--mes">\n              <div class="prod-int-node-icon">\n                <svg aria-hidden="true" viewBox="0 0 24 24">\n                  <rect x="2" y="4" width="20" height="16" rx="2"/>\n                  <path d="M6 8v8M10 8v8M14 8v8M18 8v8"/>\n                </svg>\n              </div>\n              <span class="prod-int-node-name">MES</span>\n            </div>\n\n            <div class="prod-int-node prod-int-node--wms">\n              <div class="prod-int-node-icon">\n                <svg aria-hidden="true" viewBox="0 0 24 24">\n                  <path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/>\n                  <polyline points="3.27 6.96 12 12.01 20.73 6.96"/>\n                </svg>\n              </div>\n              <span class="prod-int-node-name">WMS</span>\n            </div>\n\n            <div class="prod-int-node prod-int-node--aiot">\n              <div class="prod-int-node-icon">\n                <svg aria-hidden="true" viewBox="0 0 24 24">\n                  <circle cx="12" cy="12" r="3"/>\n                  <path d="M12 2v4M12 18v4M2 12h4M18 12h4"/>\n                  <circle cx="12" cy="12" r="8" fill="none"/>\n                </svg>\n              </div>\n              <span class="prod-int-node-name">AIoT</span>\n            </div>\n          </div>\n\n          <!-- data-flow-labels hidden (display:none in prototype) -->\n          <div class="prod-int-flow-labels" aria-hidden="true">\n            <span class="prod-int-flow-label prod-int-flow-label--top">FINANCE</span>\n            <span class="prod-int-flow-label prod-int-flow-label--right">PRODUCTION</span>\n            <span class="prod-int-flow-label prod-int-flow-label--bottom">INVENTORY</span>\n            <span class="prod-int-flow-label prod-int-flow-label--left">MACHINES</span>\n          </div>\n        </div>\n\n        <div class="prod-int-message">\n          <span class="prod-int-message-quote">“</span>\n          <p>ต่างจากโซลูชันแยกส่วนที่สร้าง Data Silo ทุกผลิตภัณฑ์ DigiWin สร้างบนฐานเดียวกัน ERP คุยกับ MES ได้ WMS รู้ว่าอะไรอยู่บนสายการผลิต AIoT ส่งข้อมูลเชิงลึกกลับไปที่การวางแผน <strong>หนึ่งฐานข้อมูล หนึ่งความจริง ไม่มีค่าใช้จ่ายการเชื่อมต่อ</strong></p>\n        </div>\n\n        <div class="prod-int-cta-wrapper">\n          <a href="/demo/" class="prod-int-cta">พูดคุยเรื่องโรงงานของคุณ</a>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Why"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Why: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Why: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="prod-why-section">\n      <div class="prod-why-inner">\n        <div class="prod-why-header">\n          <p class="prod-why-label">ข้อได้เปรียบ DigiWin</p>\n          <h2 class="prod-why-title">ทำไมต้องเลือกผลิตภัณฑ์ DigiWin?</h2>\n        </div>\n        <div class="prod-why-grid">\n          \n          <div class="prod-why-card">\n            <div class="prod-why-card-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24">\n                <circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/>\n              </svg>\n            </div>\n            <h3 class="prod-why-card-title">มุ่งเน้นเฉพาะโรงงานผลิต</h3>\n            <p class="prod-why-card-desc">เราไม่ขายให้ธนาคาร ห้างสรรพสินค้า หรือโรงพยาบาล <span class="dw-years">44</span> ปีที่มุ่งเน้นเฉพาะการผลิตหมายความว่าฟีเจอร์ทุกอย่างสร้างมาสำหรับสายการผลิต ไม่ใช่ดัดแปลงมาจากอุตสาหกรรมอื่น</p>\n          </div>\n          <div class="prod-why-card">\n            <div class="prod-why-card-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24">\n                <path d="M3 3v18h18"/><path d="M18.7 8l-5.1 5.2-2.8-2.7L7 14.3"/>\n              </svg>\n            </div>\n            <h3 class="prod-why-card-title">เติบโตไปพร้อมกับคุณ</h3>\n            <p class="prod-why-card-desc">เริ่มต้นจากสิ่งที่คุณต้องการวันนี้ เพิ่มความสามารถเมื่อคุณเติบโต จากโรงงาน 20 คนถึงองค์กรหลายสาขา—ระบบนิเวศเดิม พาร์ทเนอร์เดิม ไม่ต้องเริ่มใหม่</p>\n          </div>\n          <div class="prod-why-card">\n            <div class="prod-why-card-icon">\n              <svg aria-hidden="true" viewBox="0 0 24 24">\n                <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M23 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/>\n              </svg>\n            </div>\n            <h3 class="prod-why-card-title">ทีมสนับสนุนในไทย</h3>\n            <p class="prod-why-card-desc">ทีมมากกว่า 50 คนในประเทศไทย สนับสนุนสองภาษา ความเชี่ยวชาญด้าน Implementation ในท้องถิ่น พร้อมองค์ความรู้ด้านการผลิตระดับโลก <span class="dw-years">44</span> ปี</p>\n          </div>\n        </div>\n      </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ไม่แน่ใจจะเริ่มจากตรงไหน?"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ไม่แน่ใจจะเริ่มจากตรงไหน?: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ไม่แน่ใจจะเริ่มจากตรงไหน?: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="prod-cta-section">\n    <div class="prod-cta-super-d" aria-hidden="true"></div>\n    \n    <div class="prod-cta-container">\n      <h2 class="prod-cta-title">ไม่แน่ใจว่าจะเริ่มจากตรงไหน?</h2>\n      <p class="prod-cta-subtitle">บอกเราเกี่ยวกับโรงงานของคุณ แล้วเราจะแนะนำโซลูชันที่เหมาะกับความต้องการ ไม่มีข้อผูกมัด ไม่มีแรงกดดัน—แค่ความชัดเจน</p>\n      <div class="prod-cta-btn-row">\n        <a href="/th/demo/" class="prod-cta-btn prod-cta-btn--primary">พูดคุยกับเรา</a>\n        <a href="/industries/" class="prod-cta-btn prod-cta-btn--ghost">ดูตามอุตสาหกรรม</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100776;

-- Step 2: Update Divi 5 custom CSS
DELETE FROM wp_postmeta WHERE post_id = 100776 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100776, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === PRODUCTS HERO (S1) === */\n.prod-hero-section{padding:160px 0 120px;background:linear-gradient(165deg,#000432 0%,#001080 40%,#000864 100%);position:relative;overflow:hidden;min-height:85vh;display:flex;align-items:center;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n\n/* Super D background decoration */\n.prod-hero-d-bg{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.1;pointer-events:none;z-index:0}\n\n/* Grain overlay */\n.prod-hero-grain::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.prod-hero-grain{position:absolute;inset:0;z-index:1;opacity:0.16;pointer-events:none}\n\n/* Light-leak radial */\n.prod-hero-section::after{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background:radial-gradient(ellipse at 80% 20%,rgba(0,175,240,0.15) 0%,transparent 50%),radial-gradient(ellipse at 20% 80%,rgba(139,92,246,0.1) 0%,transparent 40%);pointer-events:none;z-index:1}\n\n/* SVG ecosystem illustration */\n.prod-hero-ecosystem{position:absolute;top:0;left:0;right:0;bottom:0;overflow:hidden;pointer-events:none;z-index:0}\n.prod-hero-ecosystem svg{position:absolute;width:100%;height:100%}\n\n/* Inner grid layout */\n.prod-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;display:grid;grid-template-columns:1fr 1fr;gap:80px;align-items:center;position:relative;z-index:2}\n\n/* Content column */\n.prod-hero-content{animation:prod-hero-slide-up 0.8s ease-out}\n\n/* Badge */\n.prod-hero-badge{display:inline-flex;align-items:center;gap:10px;background:rgba(0,175,240,0.1);border:1px solid rgba(0,175,240,0.3);padding:10px 20px;border-radius:50px;color:#00AFF0;font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:28px}\n.prod-hero-badge::before{content:\'\';width:8px;height:8px;background:#00AFF0;border-radius:50%;animation:prod-hero-pulse 2s ease-in-out infinite}\n\n/* Title */\n.prod-hero-title{font-family:\'Noto Sans\',sans-serif;font-size:clamp(40px,5vw,56px);font-weight:700;color:#ffffff;margin:0 0 24px;line-height:1.1;letter-spacing:-0.03em;padding:0}\n.prod-hero-hl{color:#00AFF0}\n\n/* Subtitle */\n.prod-hero-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:19px;color:rgba(255,255,255,0.85);max-width:520px;margin:0 0 40px;line-height:1.7;padding:0}\n\n/* Button */\n.prod-hero-btn-wrap{margin-top:32px;margin-bottom:16px}\n\n.prod-hero-cta-wrapper{text-align:center}\n.prod-hero-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;line-height:1.6;color:#ffffff;background:#006dac;padding:16px 32px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 14px rgba(0,175,240,0.35)}\n.prod-hero-cta:hover{background:#0099D6;transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,175,240,0.3)}\n\n/* Stats row */\n.prod-hero-stats{display:flex;gap:48px;padding-top:32px;border-top:1px solid rgba(255,255,255,0.1)}\n.prod-hero-stat{text-align:left}\n.prod-hero-stat-number{font-family:\'Noto Sans\',sans-serif;font-size:36px;font-weight:800;color:#00AFF0;letter-spacing:-0.02em}\n.prod-hero-stat-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;color:rgba(255,255,255,0.85);text-transform:uppercase;letter-spacing:0.1em;margin-top:6px}\n\n/* ── Stack visual (right column) ── */\n.prod-hero-stack-visual{position:relative;height:500px;perspective:1200px;animation:prod-hero-slide-up 1s ease-out 0.2s both}\n.prod-hero-stack-container{position:relative;width:100%;height:100%;transform-style:preserve-3d}\n\n/* Stack layers */\n.prod-hero-layer{position:absolute;right:0;width:220px;padding:16px 20px;border-radius:12px;display:flex;align-items:center;gap:14px;font-family:\'Noto Sans\',sans-serif;font-size:14px;font-weight:600;color:#ffffff;box-shadow:0 8px 32px rgba(0,0,0,0.3),inset 0 1px 0 rgba(255,255,255,0.15);transition:all 0.3s ease;cursor:default;overflow:hidden}\n.prod-hero-layer:hover{transform:translateX(-8px);box-shadow:0 12px 40px rgba(0,0,0,0.4)}\n.prod-hero-layer::before{content:\'\';position:absolute;top:0;left:-100%;width:50%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.15),transparent);animation:prod-hero-wave-flow 3s ease-in-out infinite}\n\n.prod-hero-layer-icon{width:36px;height:36px;display:flex;align-items:center;justify-content:center;background:rgba(255,255,255,0.2);border-radius:10px;flex-shrink:0}\n.prod-hero-layer-icon svg{width:20px;height:20px;stroke:currentColor;fill:none;stroke-width:2}\n\n/* Layer variants */\n.prod-hero-layer--aiot{top:40px;background:linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%);animation:prod-hero-float 4s ease-in-out infinite}\n.prod-hero-layer--mes{top:120px;right:40px;background:linear-gradient(135deg,#10b981 0%,#02D28C 100%);animation:prod-hero-float 4s ease-in-out infinite 0.3s}\n.prod-hero-layer--wms{top:200px;right:20px;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);animation:prod-hero-float 4s ease-in-out infinite 0.6s}\n.prod-hero-layer--erp{top:280px;right:60px;background:linear-gradient(135deg,#00AFF0 0%,#003CC8 100%);animation:prod-hero-float 4s ease-in-out infinite 0.9s}\n\n/* Data particles */\n.prod-hero-particles{position:absolute;width:100%;height:100%;pointer-events:none}\n.prod-hero-particle{position:absolute;width:6px;height:6px;background:#00AFF0;border-radius:50%;box-shadow:0 0 10px rgba(0,175,240,0.4);animation:prod-hero-data-rise 2s ease-in-out infinite}\n.prod-hero-particle:nth-child(1){left:35%;animation-delay:0s}\n.prod-hero-particle:nth-child(2){left:50%;animation-delay:0.5s}\n.prod-hero-particle:nth-child(3){left:65%;animation-delay:1s}\n.prod-hero-particle:nth-child(4){left:42%;animation-delay:1.5s}\n.prod-hero-particle:nth-child(5){left:58%;animation-delay:2s}\n\n/* ── Keyframes ── */\n@keyframes prod-hero-slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes prod-hero-pulse{0%,100%{opacity:0.5;transform:scale(1)}50%{opacity:1;transform:scale(1.3)}}\n@keyframes prod-hero-float{0%,100%{transform:translateY(0)}50%{transform:translateY(-12px)}}\n@keyframes prod-hero-wave-flow{0%{left:-100%}100%{left:200%}}\n@keyframes prod-hero-data-rise{0%{bottom:20%;opacity:0}50%{opacity:0.8}100%{bottom:80%;opacity:0}}\n\n/* ── Responsive ── */\n@media(max-width:1024px){\n  .prod-hero-inner{grid-template-columns:1fr;text-align:center;gap:40px}\n  .prod-hero-subtitle{margin-left:auto;margin-right:auto}\n  .prod-hero-stats{justify-content:center}\n  .prod-hero-stack-visual{display:none}\n}\n@media(max-width:640px){\n  .prod-hero-section{padding:120px 0 60px;min-height:auto}\n  .prod-hero-title{font-size:28px}\n  .prod-hero-stats{flex-direction:column;gap:20px;align-items:center}\n  .prod-hero-stat{text-align:center}\n}\n\n/* ── Reduced motion ── */\n@media(prefers-reduced-motion:reduce){\n  .prod-hero-content,.prod-hero-stack-visual,.prod-hero-badge::before,.prod-hero-layer,.prod-hero-layer::before,.prod-hero-particle,.prod-hero-section::after,.prod-hero-d-bg{animation:none !important;transition:none !important}\n  .prod-hero-content{opacity:1;transform:none}\n  .prod-hero-stack-visual{opacity:1;transform:none}\n}\n/* === PRODUCTS GRID (S2) === */\n.prod-grid-section{padding:120px 0;background:linear-gradient(180deg,#f8fafc 0%,#fff 30%,#fff 70%,#f8fafc 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.prod-grid-section::before{content:\'\';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg,transparent,#00AFF0,transparent)}\n\n/* Background layers */\n.prod-grid-ecosystem{position:absolute;top:0;left:0;right:0;bottom:0;overflow:hidden;pointer-events:none;opacity:0.6}\n.prod-grid-ecosystem svg{position:absolute;width:100%;height:100%;min-width:1200px}\n.prod-grid-dots{position:absolute;top:0;left:0;right:0;bottom:0;background-image:radial-gradient(circle,rgba(0,175,240,0.03) 1px,transparent 1px);background-size:30px 30px;pointer-events:none}\n.prod-grid-scene{position:absolute;inset:0;pointer-events:none;z-index:0}.prod-grid-scene svg{width:100%;height:100%;position:absolute;top:0;left:0;opacity:0.20}\n\n/* Section header */\n.prod-grid-header{max-width:700px;margin:0 auto 80px;text-align:center;position:relative;z-index:2}\n.prod-grid-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;color:#0369a1;text-transform:uppercase;letter-spacing:0.15em;margin-bottom:16px;display:flex;align-items:center;justify-content:center;gap:12px}\n.prod-grid-label::before,.prod-grid-label::after{content:\'\';width:40px;height:1px;background:linear-gradient(90deg,transparent,#00AFF0);flex-shrink:0}\n.prod-grid-label::after{background:linear-gradient(90deg,#00AFF0,transparent)}\n.prod-grid-title{font-family:\'Noto Sans\',sans-serif;font-size:44px;font-weight:700;color:#000864;margin:0 0 16px 0;letter-spacing:-0.02em;line-height:1.6;padding:0}\n.prod-grid-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:#5b6b80;line-height:1.6;margin:0;padding:0}\n\n/* Card grid */\n.prod-grid-cards{display:grid;grid-template-columns:repeat(2,1fr);gap:36px;max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:2}\n\n/* Card base */\n.prod-card{background:#ffffff;border-radius:24px;padding:48px;box-shadow:0 4px 24px rgba(0,0,0,0.04);border:1px solid #e8eef3;transition:all 0.5s cubic-bezier(0.4,0,0.2,1);display:flex;flex-direction:column;text-decoration:none;position:relative;overflow:hidden}\n\n/* Accent bar (top) */\n.prod-card::before{content:\'\';position:absolute;top:0;left:0;right:0;height:4px;transform:scaleX(0);transform-origin:left;transition:transform 0.5s ease}\n\n/* Glow orb (bottom-right) */\n.prod-card::after{content:\'\';position:absolute;bottom:-50px;right:-50px;width:150px;height:150px;border-radius:50%;opacity:0;transition:opacity 0.5s ease}\n\n/* Card hover */\n.prod-card:hover{transform:translateY(-12px)}\n.prod-card:hover::before{transform:scaleX(1)}\n.prod-card:hover::after{opacity:1}\n.prod-card:hover .prod-card-icon{transform:scale(1.08) rotate(-5deg)}\n.prod-card:hover .prod-card-icon::after{opacity:1}\n.prod-card:hover .prod-card-cta{gap:16px}\n.prod-card:hover .prod-card-cta svg{transform:translateX(4px)}\n\n/* Card header (icon + titles) */\n.prod-card-header{display:flex;align-items:flex-start;gap:24px;margin-bottom:28px}\n.prod-card-icon{width:80px;height:80px;border-radius:20px;display:flex;align-items:center;justify-content:center;flex-shrink:0;position:relative;transition:all 0.4s ease}\n.prod-card-icon svg{width:40px;height:40px;stroke:#ffffff;fill:none;stroke-width:1.5;stroke-linecap:round;stroke-linejoin:round}\n.prod-card-icon::after{content:\'\';position:absolute;inset:-4px;border-radius:24px;opacity:0;transition:opacity 0.4s ease;z-index:-1}\n.prod-card-titles{flex:1}\n.prod-card-eyebrow{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;text-transform:uppercase;letter-spacing:0.1em;margin-bottom:6px}\n.prod-card-title{font-family:\'Noto Sans\',sans-serif;font-size:26px;font-weight:700;color:#000864;margin:0;letter-spacing:-0.01em;line-height:1.6}\n\n/* Tagline */\n.prod-card-tagline{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:500;color:#000864;margin-bottom:16px;display:flex;align-items:center;gap:12px;line-height:1.6}\n.prod-card-tagline::before{content:\'\';width:24px;height:2px;flex-shrink:0}\n\n/* Description */\n.prod-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:16px;color:#5b6b80;line-height:1.7;margin-bottom:28px;flex:1}\n\n/* Features list */\n.prod-card-features{list-style:none;padding:0;margin:0 0 32px 0;display:grid;grid-template-columns:1fr 1fr;gap:14px}\n.prod-card-features li{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#000864;display:flex;align-items:center;gap:10px}\n.prod-card-check{width:22px;height:22px;border-radius:6px;display:flex;align-items:center;justify-content:center;flex-shrink:0}\n.prod-card-check svg{width:12px;height:12px;stroke:#ffffff;stroke-width:3;fill:none}\n\n/* CTA */\n.prod-card-cta{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:600;display:flex;align-items:center;gap:10px;margin-top:auto;transition:gap 0.3s ease}\n.prod-card-cta svg{width:20px;height:20px;stroke:currentColor;fill:none;stroke-width:2;transition:transform 0.3s ease}\n\n/* Per-product variants */\n\n.prod-card--erp::before{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.prod-card--erp::after{background:radial-gradient(circle,rgba(0,175,240,0.1) 0%,transparent 70%)}\n.prod-card-icon--erp{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.prod-card-icon--erp::after{background:linear-gradient(135deg,rgba(0,175,240,0.3),transparent)}\n.prod-card-eyebrow--erp{color:#0369a1}\n.prod-card-tagline--erp::before{background:#00AFF0}\n.prod-card-check--erp{background:linear-gradient(135deg,#00AFF0,#003CC8)}\n.prod-card-cta--erp{color:#0369a1}\n.prod-card--erp:hover{box-shadow:0 32px 80px rgba(0,175,240,0.1);border-color:transparent}\n.prod-card--mes::before{background:linear-gradient(135deg,#10b981,#02D28C)}\n.prod-card--mes::after{background:radial-gradient(circle,rgba(16,185,129,0.1) 0%,transparent 70%)}\n.prod-card-icon--mes{background:linear-gradient(135deg,#10b981,#02D28C)}\n.prod-card-icon--mes::after{background:linear-gradient(135deg,rgba(16,185,129,0.3),transparent)}\n.prod-card-eyebrow--mes{color:#10b981}\n.prod-card-tagline--mes::before{background:#10b981}\n.prod-card-check--mes{background:linear-gradient(135deg,#10b981,#02D28C)}\n.prod-card-cta--mes{color:#10b981}\n.prod-card--mes:hover{box-shadow:0 32px 80px rgba(16,185,129,0.1);border-color:transparent}\n.prod-card--wms::before{background:linear-gradient(135deg,#f59e0b,#d97706)}\n.prod-card--wms::after{background:radial-gradient(circle,rgba(245,158,11,0.1) 0%,transparent 70%)}\n.prod-card-icon--wms{background:linear-gradient(135deg,#f59e0b,#d97706)}\n.prod-card-icon--wms::after{background:linear-gradient(135deg,rgba(245,158,11,0.3),transparent)}\n.prod-card-eyebrow--wms{color:#f59e0b}\n.prod-card-tagline--wms::before{background:#f59e0b}\n.prod-card-check--wms{background:linear-gradient(135deg,#f59e0b,#d97706)}\n.prod-card-cta--wms{color:#d97706}\n.prod-card--wms:hover{box-shadow:0 32px 80px rgba(245,158,11,0.1);border-color:transparent}\n.prod-card--aiot::before{background:linear-gradient(135deg,#8b5cf6,#7c3aed)}\n.prod-card--aiot::after{background:radial-gradient(circle,rgba(139,92,246,0.1) 0%,transparent 70%)}\n.prod-card-icon--aiot{background:linear-gradient(135deg,#8b5cf6,#7c3aed)}\n.prod-card-icon--aiot::after{background:linear-gradient(135deg,rgba(139,92,246,0.3),transparent)}\n.prod-card-eyebrow--aiot{color:#8b5cf6}\n.prod-card-tagline--aiot::before{background:#8b5cf6}\n.prod-card-check--aiot{background:linear-gradient(135deg,#8b5cf6,#7c3aed)}\n.prod-card-cta--aiot{color:#8b5cf6}\n.prod-card--aiot:hover{box-shadow:0 32px 80px rgba(139,92,246,0.1);border-color:transparent}\n\n/* Divi list reset */\n.prod-grid ul,.prod-grid ol{list-style:none !important;padding:0 !important;margin:0 !important}.prod-grid li{list-style:none !important}.prod-grid li::before{display:none !important}\n\n/* Responsive: tablet */\n@media(max-width:1024px){\n  .prod-grid-cards{grid-template-columns:1fr;max-width:600px}\n  .prod-grid-title{font-size:36px}\n  .prod-grid-section{padding:80px 0}\n}\n\n/* Responsive: mobile */\n@media(max-width:768px){\n  .prod-grid-section{padding:60px 0}\n  .prod-grid-title{font-size:32px}\n  .prod-card{padding:32px}\n  .prod-card-header{flex-direction:column;gap:16px}\n  .prod-card-features{grid-template-columns:1fr}\n  .prod-grid-header{margin-bottom:48px}\n}\n\n/* Reduced motion */\n@media(prefers-reduced-motion:reduce){.prod-card,.prod-card::before,.prod-card::after,.prod-card-icon,.prod-card-icon::after,.prod-card-cta,.prod-card-cta svg{animation:none !important;transition:none !important}}\n/* === INTEGRATION (S3) === */\n.prod-int-section{padding:140px 0;background:linear-gradient(180deg,#F5F7FA 0%,#fff 100%);position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n\n/* Grid pattern overlay */\n.prod-int-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:linear-gradient(rgba(0,175,240,0.03) 1px,transparent 1px),linear-gradient(90deg,rgba(0,175,240,0.03) 1px,transparent 1px);background-size:50px 50px;pointer-events:none;z-index:1}\n\n/* Super D decoration */\n.prod-int-super-d{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.06;pointer-events:none;z-index:0}\n\n.prod-int-inner{max-width:1100px;margin:0 auto;padding:0 24px;position:relative;z-index:2}\n.prod-int-header{text-align:center;margin-bottom:60px}\n.prod-int-title{font-family:\'Noto Sans\',sans-serif;font-size:44px;font-weight:700;color:#000864;line-height:1.6;letter-spacing:-0.02em;margin:0 0 16px;padding:0}\n.prod-int-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:400;color:#5b6b80;line-height:1.6;max-width:600px;margin:0 auto;padding:0}\n\n/* === DIAGRAM === */\n.prod-int-diagram{position:relative;padding:80px 0;min-height:550px;display:flex;align-items:center;justify-content:center}\n\n/* Central hub */\n.prod-int-hub{width:140px;height:140px;background:linear-gradient(135deg,#000864 0%,#001080 100%);border-radius:50%;display:flex;flex-direction:column;align-items:center;justify-content:center;margin:0 auto;position:relative;z-index:2;box-shadow:0 20px 60px rgba(37,59,80,0.35),inset 0 1px 0 rgba(255,255,255,0.05)}\n.prod-int-hub::before,.prod-int-hub::after{content:\'\';position:absolute;border-radius:50%;border:1px solid rgba(0,175,240,0.3);animation:prod-int-pulse-ring 3s ease-out infinite}\n.prod-int-hub::before{inset:-15px;animation-delay:0s}\n.prod-int-hub::after{inset:-30px;animation-delay:1s}\n.prod-int-hub-icon{width:44px;height:44px;stroke:#00AFF0;fill:none;stroke-width:1.5;margin-bottom:8px}\n.prod-int-hub-label{font-family:\'JetBrains Mono\',monospace;font-size:10px;color:rgba(255,255,255,0.9);text-transform:uppercase;letter-spacing:0.1em}\n\n/* Orbit ring */\n.prod-int-orbit{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:380px;height:380px;border:2px dashed rgba(0,175,240,0.15);border-radius:50%}\n.prod-int-orbit::before{content:\'\';position:absolute;inset:30px;border:1px dashed rgba(0,175,240,0.1);border-radius:50%}\n\n/* Nodes */\n.prod-int-node{position:absolute;width:100px;height:100px;background:#ffffff;border:2px solid #e8eef3;border-radius:20px;display:flex;flex-direction:column;align-items:center;justify-content:center;transition:all 0.4s ease;box-shadow:0 8px 32px rgba(0,0,0,0.08);cursor:default}\n.prod-int-node-icon{width:40px;height:40px;border-radius:12px;display:flex;align-items:center;justify-content:center;margin-bottom:12px;transition:transform 0.3s ease}\n.prod-int-node-icon svg{width:26px;height:26px;stroke:#ffffff;fill:none;stroke-width:1.5}\n.prod-int-node-name{font-family:\'Noto Sans\',sans-serif;font-size:15px;font-weight:600;color:#000864}\n\n/* Node positions */\n.prod-int-node--erp{top:-30px;left:50%;transform:translateX(-50%)}\n.prod-int-node--erp .prod-int-node-icon{background:linear-gradient(135deg,#00AFF0 0%,#003CC8 100%)}\n.prod-int-node--mes{top:50%;right:-30px;transform:translateY(-50%)}\n.prod-int-node--mes .prod-int-node-icon{background:linear-gradient(135deg,#10b981 0%,#02D28C 100%)}\n.prod-int-node--wms{bottom:-30px;left:50%;transform:translateX(-50%)}\n.prod-int-node--wms .prod-int-node-icon{background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%)}\n.prod-int-node--aiot{top:50%;left:-30px;transform:translateY(-50%)}\n.prod-int-node--aiot .prod-int-node-icon{background:linear-gradient(135deg,#8b5cf6 0%,#7c3aed 100%)}\n\n/* Node hover */\n.prod-int-node:hover{box-shadow:0 16px 48px rgba(0,175,240,0.2)}\n.prod-int-node:hover .prod-int-node-icon{transform:none}\n.prod-int-node--erp:hover{border-color:#00AFF0}\n.prod-int-node--mes:hover{border-color:#10b981}\n.prod-int-node--wms:hover{border-color:#f59e0b}\n.prod-int-node--aiot:hover{border-color:#8b5cf6}\n\n/* === DATA FLOW SVG === */\n.prod-int-flow-svg{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:380px;height:380px;pointer-events:none;z-index:1}\n.prod-int-flow-line{stroke-width:2;fill:none;stroke-dasharray:10 6;animation:prod-int-data-flow 1.5s linear infinite}\n.prod-int-flow-line--erp{stroke:#00AFF0;opacity:0.6}\n.prod-int-flow-line--mes{stroke:#10b981;opacity:0.6;animation-delay:0.3s}\n.prod-int-flow-line--wms{stroke:#f59e0b;opacity:0.6;animation-delay:0.6s}\n.prod-int-flow-line--aiot{stroke:#8b5cf6;opacity:0.6;animation-delay:0.9s}\n.prod-int-flow-dot{animation:prod-int-pulse-node 1.5s ease-in-out infinite}\n.prod-int-flow-dot--erp{fill:#00AFF0}\n.prod-int-flow-dot--mes{fill:#10b981;animation-delay:0.3s}\n.prod-int-flow-dot--wms{fill:#f59e0b;animation-delay:0.6s}\n.prod-int-flow-dot--aiot{fill:#8b5cf6;animation-delay:0.9s}\n\n/* Data flow labels — hidden (matches prototype) */\n.prod-int-flow-labels{display:none}\n\n/* === MESSAGE CARD === */\n.prod-int-message{max-width:800px;margin:80px auto 0;background:#ffffff;border-radius:24px;padding:48px 64px;box-shadow:0 12px 48px rgba(0,0,0,0.08);border:1px solid #e8eef3;position:relative;overflow:hidden}\n.prod-int-message::before{content:\'\';position:absolute;top:0;left:0;right:0;height:4px;background:linear-gradient(90deg,#00AFF0,#10b981,#f59e0b,#8b5cf6);z-index:1}\n.prod-int-message-quote{position:absolute;top:24px;left:36px;font-family:\'Noto Sans\',sans-serif;font-size:100px;color:#00AFF0;opacity:0.08;line-height:1}\n.prod-int-message p{font-family:\'Noto Sans\',sans-serif;font-size:18px;color:#000864;line-height:1.85;margin:0;position:relative}\n.prod-int-message strong{color:#0369a1;font-weight:600}\n\n/* === CTA BUTTON === */\n\n.prod-int-cta-wrapper{text-align:center}\n.prod-int-cta{display:inline-flex;align-items:center;gap:8px;font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;line-height:1.6;color:#ffffff;background:#006dac;padding:16px 32px;border-radius:8px;text-decoration:none;transition:all 0.3s ease;box-shadow:0 4px 14px rgba(0,175,240,0.35)}\n.prod-int-cta:hover{background:#0099D6;transform:translateY(-2px);box-shadow:0 8px 24px rgba(0,175,240,0.3)}\n.prod-int-cta-wrapper{margin-top:48px}\n\n/* === KEYFRAMES === */\n@keyframes prod-int-pulse-ring{0%{transform:scale(1);opacity:1}100%{transform:scale(1.3);opacity:0}}\n@keyframes prod-int-data-flow{0%{stroke-dashoffset:16}100%{stroke-dashoffset:0}}\n@keyframes prod-int-pulse-node{0%,100%{opacity:0.6;r:5}50%{opacity:1;r:7}}\n\n/* === RESPONSIVE === */\n@media(max-width:1024px){\n  .prod-int-orbit{width:300px;height:300px}\n  .prod-int-flow-svg{width:300px;height:300px}\n  .prod-int-hub{width:110px;height:110px}\n  .prod-int-node{width:80px;height:80px}\n  .prod-int-node-icon{width:32px;height:32px}\n  .prod-int-node-name{font-size:11px}\n  .prod-int-node--erp,.prod-int-node--wms{left:50%;transform:translateX(-50%)}\n  .prod-int-node--erp{top:-25px}\n  .prod-int-node--wms{bottom:-25px}\n  .prod-int-node--mes{right:-25px}\n  .prod-int-node--aiot{left:-25px}\n}\n@media(max-width:768px){\n  .prod-int-section{padding:80px 20px}\n  .prod-int-title{font-size:32px}\n  .prod-int-orbit{width:280px;height:280px}\n  .prod-int-flow-svg{width:280px;height:280px}\n  .prod-int-hub{width:100px;height:100px}\n  .prod-int-hub-icon{width:36px;height:36px}\n  .prod-int-node{width:75px;height:75px;border-radius:16px}\n  .prod-int-node-icon{width:36px;height:36px;margin-bottom:6px}\n  .prod-int-node-name{font-size:11px}\n  .prod-int-node--erp{top:-25px}\n  .prod-int-node--wms{bottom:-25px}\n  .prod-int-node--mes{right:-25px}\n  .prod-int-node--aiot{left:-25px}\n  .prod-int-diagram{min-height:400px;padding:60px 0}\n  .prod-int-message{padding:32px 24px}\n}\n@media(prefers-reduced-motion:reduce){\n.prod-int-hub::before,.prod-int-hub::after,.prod-int-flow-line,.prod-int-flow-dot,.prod-int-node,.prod-int-node-icon{animation:none !important;transition:none !important}\n}\n/* === WHY DIGIWIN (S4) === */\n.prod-why-section{padding:120px 0;background:#ffffff;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.prod-why-inner{max-width:1200px;margin:0 auto;padding:0 24px}\n.prod-why-header{text-align:center;margin-bottom:72px}\n.prod-why-label{font-family:\'JetBrains Mono\',monospace;font-size:11px;font-weight:500;color:#0369a1;text-transform:uppercase;letter-spacing:0.15em;margin-bottom:16px}\n.prod-why-title{font-family:\'Noto Sans\',sans-serif;font-size:44px;font-weight:700;color:#000864;margin:0;line-height:1.6;letter-spacing:-0.02em;padding:0}\n\n/* Card grid */\n.prod-why-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:36px}\n\n/* Cards */\n.prod-why-card{text-align:center;padding:56px 36px;background:#F5F7FA;border-radius:28px;transition:all 0.5s cubic-bezier(0.4,0,0.2,1);position:relative;overflow:hidden;border:1px solid transparent}\n.prod-why-card:hover{background:#ffffff;box-shadow:0 24px 64px rgba(0,175,240,0.12);border-color:rgba(0,175,240,0.1)}\n.prod-why-card::before{content:\'\';position:absolute;top:0;left:50%;transform:translateX(-50%);width:80px;height:4px;background:linear-gradient(90deg,#00AFF0,#003CC8);border-radius:0 0 4px 4px;opacity:0;transition:opacity 0.4s ease}\n.prod-why-card:hover::before{opacity:1}\n\n/* Card icon */\n.prod-why-card-icon{width:88px;height:88px;background:#ffffff;border-radius:24px;display:flex;align-items:center;justify-content:center;margin:0 auto 28px;box-shadow:0 8px 32px rgba(0,0,0,0.06);transition:all 0.4s ease;position:relative}\n.prod-why-card-icon svg{width:40px;height:40px;stroke:#00AFF0;fill:none;stroke-width:1.5}\n.prod-why-card:hover .prod-why-card-icon{transform:scale(1.1) rotate(-5deg);box-shadow:0 16px 48px rgba(0,175,240,0.15)}\n\n/* Card text */\n.prod-why-card-title{font-family:\'Noto Sans\',sans-serif;font-size:24px;font-weight:700;color:#000864;margin:0 0 16px 0;line-height:1.6}\n.prod-why-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:16px;color:#5b6b80;line-height:1.7;margin:0}\n\n/* === RESPONSIVE === */\n@media(max-width:1024px){\n  .prod-why-grid{grid-template-columns:1fr;max-width:480px;margin:0 auto}\n}\n@media(max-width:768px){\n  .prod-why-section{padding:80px 20px}\n  .prod-why-title{font-size:32px}\n}\n@media(prefers-reduced-motion:reduce){\n.prod-why-card,.prod-why-card-icon,.prod-why-card::before{animation:none !important;transition:none !important}\n}\n/* === CTA: ไม่แน่ใจจะเริ่มจากตรงไหน? === */\n.prod-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:140px 0;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.prod-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.prod-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.prod-cta-super-d{position:absolute;top:auto;right:-10%;bottom:-20%;left:auto;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center bottom;background-size:contain;opacity:0.16;pointer-events:none;z-index:0}\n\n.prod-cta-container{position:relative;z-index:3;max-width:800px;margin:0 auto;text-align:center}\n.prod-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:clamp(36px,4.5vw,52px);color:#fff;line-height:1.6;margin:0 0 16px}\n.prod-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .prod-cta-title{font-weight:700 !important;font-size:clamp(36px,4.5vw,52px) !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .prod-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .prod-cta-container p{padding-bottom:0 !important}\n\n.prod-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.prod-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.prod-cta-btn:hover::before{left:100%}\n.prod-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.prod-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.prod-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.prod-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.prod-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.prod-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .prod-cta-title{font-size:28px;margin-bottom:16px}\n  .prod-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .prod-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .prod-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.prod-cta-btn{transition:none !important}.prod-cta-btn::before{display:none}}\n.prod-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg viewBox=\'0 0 400 400\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cfilter id=\'n\'%3E%3CfeTurbulence type=\'fractalNoise\' baseFrequency=\'0.9\' numOctaves=\'4\' stitchTiles=\'stitch\'/%3E%3C/filter%3E%3Crect width=\'100%25\' height=\'100%25\' filter=\'url(%23n)\'/%3E%3C/svg%3E");opacity:0.03;pointer-events:none;z-index:1}\n.prod-cta-title{letter-spacing:-0.02em;line-height:1.15}\n.prod-cta-subtitle{line-height:1.6;margin-bottom:48px}\n.prod-cta-container{padding:0 24px}\n.prod-cta-btn--primary:focus-visible,.prod-cta-btn--ghost:focus-visible{outline:3px solid #00AFF0;outline-offset:3px}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

